// Swift - Validate deep link
func application(_ app: UIApplication, open url: URL, options: [UIApplication.OpenURLOptionsKey: Any]) -> Bool {
    guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true),
          let host = components.host,
          allowedHosts.contains(host) else {
        return false
    }
    let sanitizedParams = components.queryItems?.reduce(into: [String: String]()) { result, item in
        if let value = item.value?.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) {
            result[item.name] = value
        }
    }
    return handleValidatedDeepLink(host: host, params: sanitizedParams ?? [:])
}

// Kotlin - Validate deep link
fun handleDeepLink(intent: Intent) {
    val uri = intent.data ?: return
    if (uri.host !in allowedHosts) return
    val sanitizedPath = uri.path?.takeIf { it.matches(validPathRegex) } ?: return
}

